### **schema.prisma** (초안)
```prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum Position {
  genetic
  past
  present
  future
}

model Color {
  id            Int            @id @default(autoincrement())
  slug          String          @unique
  display_name_ko String
  display_name_en String?
  aliases       ColorAlias[]
  positions     ColorPosition[]
}

model ColorAlias {
  id       Int    @id @default(autoincrement())
  color    Color  @relation(fields: [colorId], references: [id])
  colorId  Int
  alias    String
  lang     String?
}

model ColorPosition {
  id          Int       @id @default(autoincrement())
  color       Color     @relation(fields: [colorId], references: [id])
  colorId     Int
  position    Position
  short       String
  expansions  Json?
  keywords    Json?
}
```

