## **5) API 엔드포인트 /api/interpret**

`src/app/api/interpret/route.ts`
```ts
import { NextResponse } from "next/server";
import { PrismaClient } from "@prisma/client";
import OpenAI from "openai";

const prisma = new PrismaClient();
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function POST(req: Request) {
  const { colors, context } = await req.json();

  // 1. 색상 정규화
  const dbColors = await prisma.color.findMany({
    where: { slug: { in: colors } },
    include: { positions: true },
  });

  // 2. 스니펫 준비
  const snippets = dbColors.map(c => ({
    slug: c.slug,
    positions: c.positions
  }));

  // 3. LLM 호출
  const completion = await openai.chat.completions.create({
    model: "gpt-4o-mini",
    messages: [
      { role: "system", content: "공감적 해석 도우미. 진단 금지." },
      { role: "user", content: JSON.stringify({ colors, context, snippets }) }
    ],
  });

  const text = completion.choices[0].message?.content;
  return NextResponse.json({ result: text });
}
```

